const raw = $input.first()?.json?.body || $input.first()?.json || {};

const isWebhook = !!(raw.shipmentId || raw.exporterEmail);

const shipmentId = raw.shipmentId
  || `SHP-${new Date().getFullYear()}-${String(Date.now()).slice(-5)}`;

const documents = raw.documents || [];
const finalDocs = documents.length > 0 ? documents : [{
  name: raw.name || 'Unknown Document',
  type: 'unknown',
  driveFileId: raw.id || raw.driveFileId || null,
  url: raw.webViewLink || null
}];

const shipment = {
  shipmentId,
  exporterEmail: raw.exporterEmail || 'user@example.com',
  exporterName: raw.exporterName || 'Exporter',
  originCountry: (raw.originCountry || 'CN').toUpperCase(),
  destinationCountry: (raw.destinationCountry || 'AU').toUpperCase(),
  incoterms: (raw.incoterms || 'FOB').toUpperCase(),
  declaredValue: parseFloat(raw.declaredValue) || 0,
  currency: (raw.currency || 'USD').toUpperCase(),
  goodsDescription: raw.goodsDescription || 'General Merchandise',
  transportMode: (raw.transportMode || 'SEA').toUpperCase(),
  totalDocuments: finalDocs.length,
  caseRunId: `RUN-${Date.now()}-${Math.random().toString(36).substr(2,5).toUpperCase()}`,
  registeredAt: new Date().toISOString()
};

return finalDocs.map(doc => ({
  json: {
    shipment,
    document: {
      docId: `DOC-${Math.random().toString(36).substr(2,8).toUpperCase()}`,
      name: doc.name || 'Unnamed',
      declaredType: (doc.type || 'unknown').toLowerCase().replace(/\s+/g, '_'),
      driveFileId: doc.driveFileId || doc.id || null,
      url: doc.url || null
    }
  }
}));

const meta = $('Register Shipment Case').item.json;
const rawText = $('Extract Text from Document').item?.json?.text || 'EXTRACTION_FAILED';
const text = rawText.toLowerCase();

// ── Document Type Detection ──
const detectedType = (() => {
  if (text.includes('commercial invoice') || (text.includes('invoice') && text.includes('unit price'))) return 'COMMERCIAL_INVOICE';
  if (text.includes('packing list') || (text.includes('net weight') && text.includes('gross weight') && text.includes('cartons'))) return 'PACKING_LIST';
  if (text.includes('bill of lading') || text.includes('b/l no') || text.includes('shipper') && text.includes('notify party')) return 'BILL_OF_LADING';
  if (text.includes('airway bill') || text.includes('awb') || text.includes('air waybill')) return 'AIRWAY_BILL';
  if (text.includes('certificate of origin') || text.includes('country of origin') && text.includes('certif')) return 'CERTIFICATE_OF_ORIGIN';
  if (text.includes('dangerous goods') || text.includes('imdg') || text.includes('un number')) return 'DANGEROUS_GOODS_DECLARATION';
  if (text.includes('phytosanitary') || text.includes('plant health') || text.includes('quarantine')) return 'PHYTOSANITARY_CERTIFICATE';
  if (text.includes('insurance') && (text.includes('marine') || text.includes('cargo'))) return 'INSURANCE_CERTIFICATE';
  if (text.includes('letter of credit') || text.includes('l/c no') || text.includes('documentary credit')) return 'LETTER_OF_CREDIT';
  if (text.includes('export licence') || text.includes('export permit') || text.includes('export authorization')) return 'EXPORT_LICENCE';
  if (text.includes('material safety') || text.includes('msds') || text.includes('safety data sheet')) return 'MSDS';
  if (text.includes('fumigation') || text.includes('methyl bromide') || text.includes('heat treatment')) return 'FUMIGATION_CERTIFICATE';
  if (text.includes('customs entry') || text.includes('import declaration') || text.includes('entry number')) return 'CUSTOMS_ENTRY';
  return meta.document.declaredType?.toUpperCase().replace(/\s+/g,'_') || 'UNKNOWN';
})();

// ── Field Extraction for Cross-Document Validation ──
const extractField = (patterns, src) => {
  for (const p of patterns) {
    const m = src.match(p);
    if (m) return m[1]?.trim() || m[0]?.trim();
  }
  return null;
};

const fullText = rawText.substring(0, 14000);

// Extract key values that should be consistent across docs
const extractedFields = {
  invoiceNumber: extractField([/invoice\s*(?:no\.?|number)[:\s#]*([A-Z0-9\-\/]+)/i, /inv[\s#.:]*([A-Z0-9\-\/]{4,20})/i], fullText),
  declaredValue: extractField([/(?:total|invoice)\s*(?:amount|value)[:\s]*([\d,]+\.?\d*)/i, /(?:USD|EUR|AUD|GBP|CNY)[\s]*([\d,]+\.?\d*)/i], fullText),
  currency: extractField([/\b(USD|EUR|AUD|GBP|CNY|JPY|SGD|HKD)\b/i], fullText),
  grossWeight: extractField([/gross\s*weight[:\s]*([\d,]+\.?\d*\s*(?:kg|lbs|mt)?)/i], fullText),
  netWeight: extractField([/net\s*weight[:\s]*([\d,]+\.?\d*\s*(?:kg|lbs|mt)?)/i], fullText),
  numberOfPackages: extractField([/(?:total\s*)?(?:packages?|cartons?|boxes?|pieces?)[:\s]*([\d,]+)/i], fullText),
  hsCode: extractField([/hs\s*(?:code|tariff)[:\s#]*([\d\.]{6,12})/i, /tariff\s*(?:code|heading)[:\s]*([\d\.]{6,12})/i], fullText),
  originCountry: extractField([/country\s*of\s*origin[:\s]*([A-Za-z ]+?)(?:\n|,|$)/i], fullText),
  shipperName: extractField([/shipper[:\s]*([A-Z][A-Za-z\s&.,]{3,50})/i], fullText),
  consigneeName: extractField([/consignee[:\s]*([A-Z][A-Za-z\s&.,]{3,50})/i], fullText),
  portOfLoading: extractField([/port\s*of\s*(?:loading|origin|departure)[:\s]*([A-Za-z ,]+?)(?:\n|$)/i], fullText),
  portOfDischarge: extractField([/port\s*of\s*(?:discharge|destination|delivery)[:\s]*([A-Za-z ,]+?)(?:\n|$)/i], fullText),
  incoterms: extractField([/\b(EXW|FCA|FAS|FOB|CFR|CIF|CPT|CIP|DPU|DAP|DDP)\b/i], fullText),
  blNumber: extractField([/(?:b\/l|bill\s*of\s*lading)\s*(?:no\.?|number)[:\s#]*([A-Z0-9\-\/]+)/i], fullText)
};

// Expiry / validity check
const datePatterns = [
  /valid\s*(?:until|to|through)[:\s]*([\d]{1,2}[\/-][\d]{1,2}[\/-][\d]{2,4})/gi,
  /expir(?:y|es|ed)[:\s]*([\d]{1,2}[\/-][\d]{1,2}[\/-][\d]{2,4})/gi
];
const validityDates = [];
for (const p of datePatterns) {
  const matches = rawText.matchAll(p);
  for (const m of matches) validityDates.push(m[1]);
}

return {
  json: {
    shipment: meta.shipment,
    document: {
      ...meta.document,
      detectedType,
      extractedFields,
      validityDates,
      fullText: rawText.substring(0, 12000),
      textLength: rawText.length,
      extractionStatus: rawText === 'EXTRACTION_FAILED' ? 'FAILED' : 'SUCCESS'
    }
  }
};

const items = $input.all();
if (!items.length) return [];

const shipment = items[0].json.shipment;

// Group extracted fields by document
const docs = items.map(i => i.json);

// Gather all field values across documents for comparison
const fieldMap = {};
const fieldKeys = ['declaredValue','currency','grossWeight','netWeight','numberOfPackages','hsCode','originCountry','shipperName','consigneeName','portOfLoading','portOfDischarge','incoterms'];

for (const key of fieldKeys) {
  fieldMap[key] = docs
    .filter(d => d.document.extractedFields?.[key])
    .map(d => ({
      docId: d.document.docId,
      docName: d.document.name,
      docType: d.document.detectedType,
      value: d.document.extractedFields[key]
    }));
}

// Detect mismatches — values found in 2+ docs that differ
const mismatches = [];
const normalise = v => (v || '').toString().toLowerCase().replace(/[,\s]/g,'').trim();

for (const key of fieldKeys) {
  const entries = fieldMap[key];
  if (entries.length < 2) continue;
  const uniqueVals = [...new Set(entries.map(e => normalise(e.value)))];
  if (uniqueVals.length > 1) {
    mismatches.push({
      field: key,
      severity: ['declaredValue','hsCode','currency'].includes(key) ? 'HIGH' : 'MEDIUM',
      values: entries.map(e => `${e.docName}: ${e.value}`),
      description: `Inconsistent "${key}" across documents`
    });
  }
}

// Check declared value vs shipment header
const invoiceDoc = docs.find(d => d.document.detectedType === 'COMMERCIAL_INVOICE');
if (invoiceDoc && shipment.declaredValue > 0) {
  const invoiceVal = parseFloat((invoiceDoc.document.extractedFields.declaredValue || '0').replace(/[,]/g,''));
  if (invoiceVal > 0 && Math.abs(invoiceVal - shipment.declaredValue) / shipment.declaredValue > 0.05) {
    mismatches.push({
      field: 'declaredValueVsHeader',
      severity: 'HIGH',
      values: [`Shipment header: ${shipment.declaredValue} ${shipment.currency}`, `Invoice extracted: ${invoiceVal}`],
      description: 'Invoice value differs from declared shipment value by more than 5%'
    });
  }
}

// Mandatory document checklist by destination
const MANDATORY_BY_DEST = {
  AU: ['COMMERCIAL_INVOICE','PACKING_LIST','BILL_OF_LADING','CERTIFICATE_OF_ORIGIN'],
  US: ['COMMERCIAL_INVOICE','PACKING_LIST','BILL_OF_LADING'],
  EU: ['COMMERCIAL_INVOICE','PACKING_LIST','BILL_OF_LADING','CERTIFICATE_OF_ORIGIN'],
  UK: ['COMMERCIAL_INVOICE','PACKING_LIST','BILL_OF_LADING'],
  DEFAULT: ['COMMERCIAL_INVOICE','PACKING_LIST','BILL_OF_LADING']
};
const required = MANDATORY_BY_DEST[shipment.destinationCountry] || MANDATORY_BY_DEST.DEFAULT;
const presentTypes = docs.map(d => d.document.detectedType);
const missingDocs = required.filter(r => !presentTypes.includes(r));

// Return all items enriched with cross-check context
return items.map(item => ({
  json: {
    ...item.json,
    crossCheck: {
      mismatches,
      missingMandatoryDocs: missingDocs,
      totalDocsInPackage: docs.length,
      detectedDocTypes: presentTypes,
      crossCheckRunAt: new Date().toISOString()
    }
  }
}));

