const aiResp = $input.item.json;
let aiText = aiResp.response || aiResp.output || aiResp.text || '';
if (aiResp.content && Array.isArray(aiResp.content)) aiText = aiResp.content[0]?.text || '';

const clean = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let validation;
try {
  validation = JSON.parse(clean);
} catch(e) {
  const m = clean.match(/\{[\s\S]*\}/);
  try { validation = m ? JSON.parse(m[0]) : null; } catch(e2) { validation = null; }
  if (!validation) {
    validation = {
      docId: 'PARSE_ERROR', complianceStatus: 'HOLD', riskLevel: 'HIGH',
      confidenceScore: 0, errors: [{ field: 'system', issue: 'AI response parse failed', severity: 'HIGH', fix: 'Retry or review manually' }],
      passedChecks: [], warnings: [], missingFields: [], crossDocumentIssues: [],
      documentSummary: 'Validation processing error — manual review required.',
      requiresBrokerReview: true, canDispatch: false
    };
  }
}

const up = $('Cross-Document Consistency Engine').item.json;
return {
  json: {
    shipment: up.shipment,
    document: up.document,
    crossCheck: up.crossCheck,
    validation,
    validatedAt: new Date().toISOString()
  }
};

const items = $input.all();
if (!items.length) return [{ json: { error: 'No results to aggregate' } }];

const shipment = items[0].json.shipment;
const crossCheck = items[0].json.crossCheck;

const docResults = items.map(i => ({
  docId: i.json.document.docId,
  name: i.json.document.name,
  confirmedType: i.json.validation.confirmedType || i.json.document.detectedType,
  complianceStatus: i.json.validation.complianceStatus,
  riskLevel: i.json.validation.riskLevel,
  isExpiredOrInvalid: i.json.validation.isExpiredOrInvalid,
  hsCodeFound: i.json.validation.hsCodeFound,
  hsCodeValid: i.json.validation.hsCodeValid,
  hsCodeSuggestion: i.json.validation.hsCodeSuggestion,
  restrictedGoodsFlag: i.json.validation.restrictedGoodsFlag,
  sanctionRiskFlag: i.json.validation.sanctionRiskFlag,
  errors: i.json.validation.errors || [],
  warnings: i.json.validation.warnings || [],
  missingFields: i.json.validation.missingFields || [],
  passedChecks: i.json.validation.passedChecks || [],
  dutyImplications: i.json.validation.dutyImplications,
  documentSummary: i.json.validation.documentSummary,
  requiresBrokerReview: i.json.validation.requiresBrokerReview,
  canDispatch: i.json.validation.canDispatch
}));

// Overall shipment status
const hasReject = docResults.some(d => d.complianceStatus === 'REJECT');
const hasHold = docResults.some(d => d.complianceStatus === 'HOLD');
const hasCritical = docResults.some(d => d.riskLevel === 'CRITICAL');
const hasRestricted = docResults.some(d => d.restrictedGoodsFlag);
const hasSanction = docResults.some(d => d.sanctionRiskFlag);
const missingDocs = crossCheck.missingMandatoryDocs || [];
const crossMismatches = crossCheck.mismatches || [];

const overallStatus = (hasReject || hasCritical || hasRestricted || hasSanction || missingDocs.length > 0)
  ? 'REJECT'
  : hasHold
    ? 'HOLD'
    : 'CLEAR';

const totalErrors = docResults.reduce((s, d) => s + d.errors.length, 0);
const criticalErrors = docResults.reduce((s, d) => s + d.errors.filter(e => e.severity === 'CRITICAL').length, 0);
const highErrors = docResults.reduce((s, d) => s + d.errors.filter(e => e.severity === 'HIGH').length, 0);

// Flat remediation list
const allFixes = [];
if (missingDocs.length > 0) allFixes.push(`MISSING DOCS: Provide — ${missingDocs.join(', ')}`);
for (const m of crossMismatches) allFixes.push(`MISMATCH [${m.severity}]: ${m.description} — Values: ${m.values.join(' | ')}`);
for (const doc of docResults) {
  for (const err of doc.errors) {
    allFixes.push(`[${doc.name}] ${err.field}: ${err.issue} → FIX: ${err.fix}`);
  }
}

return [{
  json: {
    shipment,
    overallStatus,
    summary: {
      totalDocuments: docResults.length,
      cleared: docResults.filter(d => d.complianceStatus === 'CLEAR').length,
      held: docResults.filter(d => d.complianceStatus === 'HOLD').length,
      rejected: docResults.filter(d => d.complianceStatus === 'REJECT').length,
      expired: docResults.filter(d => d.isExpiredOrInvalid).length,
      totalErrors, criticalErrors, highErrors,
      crossDocMismatches: crossMismatches.length,
      missingMandatoryDocs: missingDocs.length,
      restrictedGoodsFlag: hasRestricted,
      sanctionRiskFlag: hasSanction
    },
    missingMandatoryDocs: missingDocs,
    crossDocumentMismatches: crossMismatches,
    documentResults: docResults,
    allRemediationSteps: allFixes,
    requiresBrokerReview: docResults.some(d => d.requiresBrokerReview) || hasCritical || hasRestricted,
    canDispatch: overallStatus === 'CLEAR',
    aggregatedAt: new Date().toISOString()
  }
}];

